/* BTToast + BTToaster — Figma node 95:101 */

/* ── Toast card ────────────────────────────────────────────────────── */
.bt-toast {
  width: 320px;
  box-sizing: border-box;
  padding: var(--space-md);
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-elevation-md);
  font-family: var(--typography-font-family-sans);
  display: flex;
  align-items: flex-start;
  gap: var(--space-sm);
  pointer-events: auto;
}

.bt-toast__icon {
  flex: 0 0 16px;
  width: 16px;
  height: 16px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

/* component-specific icon palette — Figma node 95:101 */
.bt-toast__icon--success { color: #0a632f; }
.bt-toast__icon--error   { color: #991515; }
.bt-toast__icon--warning { color: #8f760b; }
.bt-toast__icon--info    { color: #0f5e81; }

.bt-toast__body {
  flex: 1 1 auto;
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  min-width: 0;
}

.bt-toast__row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-sm);
  width: 100%;
}

.bt-toast__title {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  margin: 0;
}

.bt-toast__description {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  margin: 0;
}

.bt-toast__action {
  align-self: flex-start;
  margin-top: var(--space-xs);
  padding: var(--space-sm);
  font-family: inherit;
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  background: transparent;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  cursor: pointer;
}

.bt-toast__action:hover { opacity: 0.85; }

.bt-toast__close {
  flex: 0 0 16px;
  width: 16px;
  height: 16px;
  padding: 0;
  background: transparent;
  border: 0;
  cursor: pointer;
  color: var(--text-secondary);
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.bt-toast__close:hover { opacity: 0.7; }

/* Default variant: title + close, justified */
.bt-toast--default .bt-toast__body { flex-direction: row; align-items: center; }
.bt-toast--default .bt-toast__body .bt-toast__title { flex: 1 1 auto; }

/* ── Toaster container ─────────────────────────────────────────────── */
.bt-toaster {
  position: fixed;
  z-index: 9999;
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
  padding: var(--space-lg);
  pointer-events: none;
  box-sizing: border-box;
}

.bt-toaster--top-left      { top: 0; inset-inline-start: 0; align-items: flex-start; }
.bt-toaster--top-center    { top: 0; left: 50%; transform: translateX(-50%); align-items: center; }
.bt-toaster--top-right     { top: 0; inset-inline-end: 0; align-items: flex-end; }
.bt-toaster--bottom-left   { bottom: 0; inset-inline-start: 0; align-items: flex-start; flex-direction: column-reverse; }
.bt-toaster--bottom-center { bottom: 0; left: 50%; transform: translateX(-50%); align-items: center; flex-direction: column-reverse; }
.bt-toaster--bottom-right  { bottom: 0; inset-inline-end: 0; align-items: flex-end; flex-direction: column-reverse; }

/* ── Animations ────────────────────────────────────────────────────── */
@keyframes bt-toast-in {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes bt-toast-in-top {
  from { opacity: 0; transform: translateY(-8px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes bt-toast-out {
  from { opacity: 1; transform: translateY(0); }
  to   { opacity: 0; transform: translateY(8px); }
}

/*
 * Vue  — TransitionGroup applies these classes directly on the .bt-toast element.
 * React — BTToaster wraps each toast in a <div> and toggles this class;
 *         the animation applies to the wrapper which carries the .bt-toast card.
 *         The wrapper is a flex child of .bt-toaster, so alignment is inherited.
 */
.bt-toast-enter-active { animation: bt-toast-in 0.2s ease both; }
.bt-toast-leave-active { animation: bt-toast-out 0.15s ease both; }

.bt-toaster--top-left .bt-toast-enter-active,
.bt-toaster--top-center .bt-toast-enter-active,
.bt-toaster--top-right .bt-toast-enter-active {
  animation: bt-toast-in-top 0.2s ease both;
}

/**
 * BTToast — single toast card.
 *
 * Figma source: node 95:101 (file WANr9drWYNYbMPuT2sMeHi).
 *
 * @example
 *   <BTToast item={item} onClose={() => dismiss(item.id)} />
 */
import './BTToast.css';
import type { BTToastItem } from './BTToast.types';

interface BTToastProps {
  item: BTToastItem;
  onClose: () => void;
}

function CloseIcon(): JSX.Element {
  return (
    <svg
      width="16"
      height="16"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <path d="M18 6 L6 18" />
      <path d="M6 6 L18 18" />
    </svg>
  );
}

function StatusIcon({ type }: { type: BTToastItem['type'] }): JSX.Element | null {
  if (type === 'success') {
    return (
      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="12" cy="12" r="10" />
        <path d="M7 12 L10 15 L17 8" />
      </svg>
    );
  }
  if (type === 'error') {
    return (
      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="12" cy="12" r="10" />
        <path d="M12 7 L12 13" />
        <path d="M12 16 L12 17" />
      </svg>
    );
  }
  if (type === 'warning') {
    return (
      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M10.29 3.86 L1.82 18 A2 2 0 0 0 3.64 21 L20.36 21 A2 2 0 0 0 22.18 18 L13.71 3.86 A2 2 0 0 0 10.29 3.86 Z" />
        <path d="M12 9 L12 13" />
        <path d="M12 16 L12 17" />
      </svg>
    );
  }
  if (type === 'info') {
    return (
      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="12" cy="12" r="10" />
        <path d="M12 16 L12 12" />
        <path d="M12 8 L12 9" />
      </svg>
    );
  }
  return null;
}

// Auto-detect direction from text content — the toast is portaled to
// <body> so ancestor dir="rtl" doesn't reach it. Any Arabic/Hebrew glyph
// in the title or description flips the toast to RTL.
const RTL_GLYPH = /[֐-ۿݐ-ݿࢠ-ࣿיִ-﷿ﹰ-﻿]/;

export function BTToast({ item, onClose }: BTToastProps): JSX.Element {
  const isDefault = item.type === 'default';
  const isDescription = item.type === 'description';
  const hasIcon = !isDefault && !isDescription;
  const dir: 'ltr' | 'rtl' = RTL_GLYPH.test(
    `${item.title ?? ''} ${(item as { description?: string }).description ?? ''}`,
  )
    ? 'rtl'
    : 'ltr';

  return (
    <div className={`bt-toast bt-toast--${item.type}`} dir={dir} role="status" aria-live="polite">
      {hasIcon && (
        <span className={`bt-toast__icon bt-toast__icon--${item.type}`} aria-hidden="true">
          <StatusIcon type={item.type} />
        </span>
      )}

      <div className="bt-toast__body">
        {isDefault ? (
          <>
            <p className="bt-toast__title">{item.title}</p>
            <button type="button" className="bt-toast__close" aria-label="Close" onClick={onClose}>
              <CloseIcon />
            </button>
          </>
        ) : isDescription ? (
          <>
            <div className="bt-toast__row">
              <p className="bt-toast__title">{item.title}</p>
              <button type="button" className="bt-toast__close" aria-label="Close" onClick={onClose}>
                <CloseIcon />
              </button>
            </div>
            {item.description && <p className="bt-toast__description">{item.description}</p>}
            {item.actionLabel && (
              <button type="button" className="bt-toast__action" onClick={() => item.onAction?.()}>
                {item.actionLabel}
              </button>
            )}
          </>
        ) : (
          <>
            <div className="bt-toast__row">
              <p className="bt-toast__title">{item.title}</p>
              <button type="button" className="bt-toast__close" aria-label="Close" onClick={onClose}>
                <CloseIcon />
              </button>
            </div>
            {item.description && <p className="bt-toast__description">{item.description}</p>}
          </>
        )}
      </div>
    </div>
  );
}

// BTToast / BTToaster types — Figma node 95:101.

export type BTToastType =
  | 'default'
  | 'success'
  | 'error'
  | 'warning'
  | 'info'
  | 'description';

export type BTToastPosition =
  | 'top-left'
  | 'top-center'
  | 'top-right'
  | 'bottom-left'
  | 'bottom-center'
  | 'bottom-right';

export interface BTToastItem {
  id: string;
  type: BTToastType;
  title: string;
  description?: string;
  actionLabel?: string;
  onAction?: () => void;
  /** ms — 0 means persistent (no auto-dismiss). */
  duration: number;
}

export interface BTToastOptions {
  description?: string;
  actionLabel?: string;
  onAction?: () => void;
  /** ms — 0 means persistent. Defaults to 4000. */
  duration?: number;
}

/**
 * BTToaster — global toast container (React).
 *
 * Mount once at the application root. Reads from the imperative `toast`
 * singleton store. 9 positions supported; default = `bottom-right`.
 *
 * @example
 *   <BTToaster position="bottom-right" />
 */
import { useEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { useToast } from './useToast';
import { BTToast } from './BTToast';
import type { BTToastItem, BTToastPosition } from './BTToast.types';
import './BTToast.css';

interface BTToasterProps {
  position?: BTToastPosition;
}

/** Augments a BTToastItem with an exit-animation flag. */
interface LocalToast extends BTToastItem {
  exiting: boolean;
}

/** Duration (ms) of the bt-toast-out leave animation. */
const LEAVE_DURATION_MS = 150;

export function BTToaster({ position = 'bottom-right' }: BTToasterProps): JSX.Element | null {
  const { toasts, remove } = useToast();
  const [mounted, setMounted] = useState(false);
  const [localToasts, setLocalToasts] = useState<LocalToast[]>([]);
  // exitTimers tracks pending cleanup timeouts so we never double-schedule.
  const exitTimers = useRef<Record<string, ReturnType<typeof setTimeout>>>({});

  // Mount guard — avoids SSR mismatch.
  useEffect(() => {
    setMounted(true);
  }, []);

  // Effect 1: sync the external store → local list.
  // When a toast is removed from the store (auto-dismiss or manual), mark it
  // as `exiting: true` so the leave animation plays before we drop it.
  useEffect(() => {
    setLocalToasts((prev) => {
      const storeIds = new Set(toasts.map((t) => t.id));

      // Mark toasts that are no longer in the store as exiting.
      const updated = prev.map((t): LocalToast => {
        if (!t.exiting && !storeIds.has(t.id)) {
          return { ...t, exiting: true };
        }
        return t;
      });

      // Append brand-new toasts that aren't in the local list yet.
      const existingIds = new Set(prev.map((t) => t.id));
      const added: LocalToast[] = toasts
        .filter((t) => !existingIds.has(t.id))
        .map((t) => ({ ...t, exiting: false }));

      return [...updated, ...added];
    });
  }, [toasts]);

  // Effect 2: schedule cleanup for toasts in the exiting state.
  // Runs whenever localToasts changes, picks up newly-exiting entries, and
  // removes them from local state after the CSS animation finishes.
  useEffect(() => {
    localToasts.forEach((t) => {
      if (t.exiting && !exitTimers.current[t.id]) {
        exitTimers.current[t.id] = setTimeout(() => {
          setLocalToasts((cur) => cur.filter((x) => x.id !== t.id));
          delete exitTimers.current[t.id];
        }, LEAVE_DURATION_MS);
      }
    });
  }, [localToasts]);

  // Cleanup all pending timers on unmount.
  useEffect(() => {
    return () => {
      Object.values(exitTimers.current).forEach(clearTimeout);
    };
  }, []);

  if (!mounted || typeof document === 'undefined') return null;

  function handleClose(id: string): void {
    remove(id); // Removes from store → Effect 1 marks it exiting → Effect 2 schedules cleanup
  }

  return createPortal(
    <div
      className={`bt-toaster bt-toaster--${position}`}
      role="region"
      aria-label="Notifications"
    >
      {localToasts.map((t: LocalToast) => (
        <div
          key={t.id}
          className={t.exiting ? 'bt-toast-leave-active' : 'bt-toast-enter-active'}
        >
          <BTToast item={t} onClose={() => handleClose(t.id)} />
        </div>
      ))}
    </div>,
    document.body,
  );
}

export { BTToast } from './BTToast';
export { BTToaster } from './BTToaster';
export { toast, useToast } from './useToast';
export type {
  BTToastItem,
  BTToastOptions,
  BTToastPosition,
  BTToastType,
} from './BTToast.types';

import { useSyncExternalStore } from 'react';
import type {
  BTToastItem,
  BTToastOptions,
  BTToastType,
} from './BTToast.types';

let _id = 0;
let _toasts: BTToastItem[] = [];
const _listeners = new Set<() => void>();

function notify(): void {
  _listeners.forEach((cb) => cb());
}

function subscribe(cb: () => void): () => void {
  _listeners.add(cb);
  return () => {
    _listeners.delete(cb);
  };
}

function getSnapshot(): BTToastItem[] {
  return _toasts;
}

function add(item: Omit<BTToastItem, 'id'>): string {
  const id = String(++_id);
  _toasts = [..._toasts, { ...item, id }];
  notify();
  if (item.duration > 0) {
    setTimeout(() => remove(id), item.duration);
  }
  return id;
}

function remove(id: string): void {
  const next = _toasts.filter((t) => t.id !== id);
  if (next.length !== _toasts.length) {
    _toasts = next;
    notify();
  }
}

function make(type: BTToastType) {
  return (title: string, opts?: BTToastOptions): string =>
    add({
      type,
      title,
      description: opts?.description,
      actionLabel: opts?.actionLabel,
      onAction: opts?.onAction,
      duration: opts?.duration ?? 4000,
    });
}

/**
 * Imperative toast API. Call from anywhere in your app:
 *
 *   toast('Hello');
 *   toast.success('Saved!');
 *   toast.error('Failed', { description: 'Please retry' });
 *   toast.dismiss(id);
 */
export const toast = Object.assign(make('default'), {
  success: make('success'),
  error: make('error'),
  warning: make('warning'),
  info: make('info'),
  description: make('description'),
  dismiss: remove,
});

/** Reactive accessor used by `<BTToaster>`. */
export function useToast(): {
  toasts: BTToastItem[];
  remove: (id: string) => void;
} {
  const toasts = useSyncExternalStore(subscribe, getSnapshot, getSnapshot);
  return { toasts, remove };
}
